# Flow Oriented Data Flow Model - Intermediate Example
# Demonstrates multiple transformation processes in a pipeline

class OrderSource:
    """External Entity: Customer order input"""
    def get_orders(self):
        return [
            {"id": 1, "item": "laptop", "qty": 2, "price": 50000},
            {"id": 2, "item": "mouse", "qty": 5, "price": 500},
            {"id": 3, "item": "keyboard", "qty": 3, "price": 2000}
        ]

class ValidateProcess:
    """Process 1: Validate order data"""
    def validate(self, orders):
        valid_orders = []
        for order in orders:
            if order["qty"] > 0 and order["price"] > 0:
                valid_orders.append(order)
        return valid_orders

class CalculateProcess:
    """Process 2: Calculate totals"""
    def calculate(self, orders):
        for order in orders:
            order["total"] = order["qty"] * order["price"]
        return orders

class TaxProcess:
    """Process 3: Apply tax transformation"""
    def apply_tax(self, orders, tax_rate=0.18):
        for order in orders:
            order["tax"] = order["total"] * tax_rate
            order["grand_total"] = order["total"] + order["tax"]
        return orders

class OrderRepository:
    """Data Store: Persistent storage for processed orders"""
    def __init__(self):
        self.storage = []

    def save(self, orders):
        self.storage.extend(orders)
        return len(orders)

# Data Flow Execution
source = OrderSource()
validator = ValidateProcess()
calculator = CalculateProcess()
tax_calculator = TaxProcess()
repository = OrderRepository()

# Flow: Source → Validate → Calculate → Tax → Store
raw_orders = source.get_orders()
valid_orders = validator.validate(raw_orders)
calculated_orders = calculator.calculate(valid_orders)
final_orders = tax_calculator.apply_tax(calculated_orders)
saved_count = repository.save(final_orders)

print(f"Processed {saved_count} orders:")
for order in final_orders:
    print(f"  Order {order['id']}: {order['item']} - Total: ₹{order['grand_total']:.2f}")

# Flow Oriented Data Flow Model - Advanced Example
# Complete system with branching/joining flows, multiple entities and stores

from collections import deque

# External Entities
class CustomerSystem:
    """External Entity: Customer interface"""
    def send_request(self, product_id, quantity):
        return {"type": "order", "product_id": product_id, "qty": quantity}

class InventorySystem:
    """External Entity: Inventory management"""
    def check_stock(self, product_id):
        stock = {"P001": 100, "P002": 50, "P003": 200}
        return stock.get(product_id, 0)

class PaymentGateway:
    """External Entity: Payment processing"""
    def process_payment(self, amount):
        return {"status": "success", "transaction_id": "TXN12345"}

# Data Stores
class ProductCatalog:
    """Data Store: Product information"""
    def __init__(self):
        self.products = {
            "P001": {"name": "Laptop", "price": 50000},
            "P002": {"name": "Mouse", "price": 500},
            "P003": {"name": "Keyboard", "price": 2000}
        }

    def get_product(self, product_id):
        return self.products.get(product_id)

class OrderDatabase:
    """Data Store: Order persistence"""
    def __init__(self):
        self.orders = []

    def store(self, order):
        self.orders.append(order)
        return True

# Processes (Transformations)
class ValidateOrder:
    """Process: Validate order request"""
    def execute(self, order_data, product_info, stock):
        if not product_info:
            return {"valid": False, "error": "Invalid product"}
        if order_data["qty"] > stock:
            return {"valid": False, "error": "Insufficient stock"}
        return {"valid": True}

class CalculatePrice:
    """Process: Calculate order price"""
    def execute(self, order_data, product_info):
        return {
            "unit_price": product_info["price"],
            "total": order_data["qty"] * product_info["price"]
        }

class ProcessPayment:
    """Process: Handle payment (joins with price data)"""
    def execute(self, pricing, payment_gateway):
        result = payment_gateway.process_payment(pricing["total"])
        return {"payment": result, "amount": pricing["total"]}

class UpdateInventory:
    """Process: Update stock levels"""
    def execute(self, order_data, inventory_system):
        current = inventory_system.check_stock(order_data["product_id"])
        new_stock = current - order_data["qty"]
        return {"updated": True, "new_stock": new_stock}

class ConfirmOrder:
    """Process: Finalize and store order (join point)"""
    def execute(self, order_data, pricing, payment_result, order_db):
        final_order = {
            **order_data,
            "product_name": "N/A",
            "total": pricing["total"],
            "payment_status": payment_result["payment"]["status"],
            "transaction_id": payment_result["payment"]["transaction_id"]
        }
        order_db.store(final_order)
        return final_order

# Main Data Flow Execution
customer = CustomerSystem()
inventory = InventorySystem()
payment_gateway = PaymentGateway()
product_catalog = ProductCatalog()
order_database = OrderDatabase()

# Flow 1: Customer sends order request
order_request = customer.send_request("P001", 2)

# Flow 2: Branching - get product info and check stock (parallel flows)
product_info = product_catalog.get_product(order_request["product_id"])
stock_level = inventory.check_stock(order_request["product_id"])

# Flow 3: Join - Validate order with product and stock data
validator = ValidateOrder()
validation = validator.execute(order_request, product_info, stock_level)

if validation["valid"]:
    # Flow 4: Calculate pricing
    calculator = CalculatePrice()
    pricing = calculator.execute(order_request, product_info)

    # Flow 5: Process payment (joins pricing data)
    payment_processor = ProcessPayment()
    payment_result = payment_processor.execute(pricing, payment_gateway)

    # Flow 6: Update inventory (parallel with payment)
    inventory_updater = UpdateInventory()
    inventory_updater.execute(order_request, inventory)

    # Flow 7: Final join - Confirm and store order
    confirmer = ConfirmOrder()
    final_order = confirmer.execute(order_request, pricing, payment_result, order_database)

    print("Order Confirmed!")
    print(f"Product: {product_info['name']}")
    print(f"Quantity: {order_request['qty']}")
    print(f"Total: ₹{pricing['total']}")
    print(f"Payment: {payment_result['payment']['status']}")
else:
    print(f"Order Failed: {validation['error']}")
